SET NAMES utf8mb4; CREATE DATABASE IF NOT EXISTS usemed CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci; USE usemed;
DROP TABLE IF EXISTS document_logs, documents, ai_risk_assessments, ventilator_waveforms, ventilator_cases, appointments, vaccines, injections, medications, treatments, diabetes_followups, visits, patient_conditions, patient_accounts, patients, staff_users, support_tickets;

CREATE TABLE staff_users(id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(50) UNIQUE, password_hash VARCHAR(255), role ENUM('doctor','admin') NOT NULL, full_name VARCHAR(150), department VARCHAR(100), is_active TINYINT DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE patients(id INT AUTO_INCREMENT PRIMARY KEY, hn VARCHAR(30) UNIQUE NOT NULL, citizen_id VARCHAR(30), first_name VARCHAR(100), last_name VARCHAR(100), sex ENUM('ชาย','หญิง','อื่นๆ') DEFAULT 'หญิง', birthdate DATE, age INT, weight DECIMAL(6,2), height DECIMAL(6,2), bmi DECIMAL(5,2), blood_type VARCHAR(5), phone VARCHAR(30), address TEXT, allergy TEXT, menstrual_history TEXT, pregnancy_history TEXT, abortion_history TEXT, sexual_history TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE patient_accounts(id INT AUTO_INCREMENT PRIMARY KEY, patient_id INT, password_hash VARCHAR(255), is_active TINYINT DEFAULT 1, FOREIGN KEY(patient_id) REFERENCES patients(id) ON DELETE CASCADE);
CREATE TABLE patient_conditions(id INT AUTO_INCREMENT PRIMARY KEY, patient_id INT, condition_name VARCHAR(150), diagnosed_date DATE NULL, note TEXT, FOREIGN KEY(patient_id) REFERENCES patients(id) ON DELETE CASCADE);
CREATE TABLE visits(id INT AUTO_INCREMENT PRIMARY KEY, patient_id INT, visit_date DATE, hospital_name VARCHAR(150), visit_type ENUM('OPD','IPD','ER','Telemedicine') DEFAULT 'OPD', department VARCHAR(120), ward VARCHAR(120), bed_no VARCHAR(50), doctor_name VARCHAR(150), chief_complaint TEXT, diagnosis TEXT, symptom_note TEXT, surgery_flag TINYINT DEFAULT 0, major_surgery_flag TINYINT DEFAULT 0, surgery_detail TEXT, anesthesia_type VARCHAR(100), sbp INT, dbp INT, pulse INT, temperature DECIMAL(4,1), spo2 INT, created_by INT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(patient_id) REFERENCES patients(id) ON DELETE CASCADE);
CREATE TABLE diabetes_followups(id INT AUTO_INCREMENT PRIMARY KEY, patient_id INT, visit_id INT NULL, followup_date DATE, diabetes_type VARCHAR(80), hba1c DECIMAL(4,1), fpg DECIMAL(6,1), c_peptide DECIMAL(6,2), sbp INT, dbp INT, bmi DECIMAL(5,2), ldl DECIMAL(6,1), hdl DECIMAL(6,1), tg DECIMAL(6,1), egfr DECIMAL(6,1), uacr DECIMAL(7,1), metformin TINYINT DEFAULT 0, insulin TINYINT DEFAULT 0, glp1 TINYINT DEFAULT 0, note TEXT, FOREIGN KEY(patient_id) REFERENCES patients(id) ON DELETE CASCADE, FOREIGN KEY(visit_id) REFERENCES visits(id) ON DELETE SET NULL);
CREATE TABLE treatments(id INT AUTO_INCREMENT PRIMARY KEY, visit_id INT, treatment_type VARCHAR(80), detail TEXT, outcome_note TEXT, FOREIGN KEY(visit_id) REFERENCES visits(id) ON DELETE CASCADE);
CREATE TABLE medications(id INT AUTO_INCREMENT PRIMARY KEY, visit_id INT, drug_name VARCHAR(150), dose VARCHAR(120), route VARCHAR(80), frequency VARCHAR(100), duration VARCHAR(100), note TEXT, FOREIGN KEY(visit_id) REFERENCES visits(id) ON DELETE CASCADE);
CREATE TABLE injections(id INT AUTO_INCREMENT PRIMARY KEY, visit_id INT, injection_name VARCHAR(150), dose VARCHAR(120), route VARCHAR(80), note TEXT, FOREIGN KEY(visit_id) REFERENCES visits(id) ON DELETE CASCADE);
CREATE TABLE vaccines(id INT AUTO_INCREMENT PRIMARY KEY, visit_id INT, vaccine_name VARCHAR(150), dose_no VARCHAR(50), lot_no VARCHAR(80), injection_date DATE, note TEXT, FOREIGN KEY(visit_id) REFERENCES visits(id) ON DELETE CASCADE);
CREATE TABLE appointments(id INT AUTO_INCREMENT PRIMARY KEY, patient_id INT, visit_id INT NULL, appointment_date DATE, department VARCHAR(120), doctor_name VARCHAR(150), reason TEXT, status ENUM('scheduled','done','missed','cancelled') DEFAULT 'scheduled', FOREIGN KEY(patient_id) REFERENCES patients(id) ON DELETE CASCADE, FOREIGN KEY(visit_id) REFERENCES visits(id) ON DELETE SET NULL);
CREATE TABLE documents(id INT AUTO_INCREMENT PRIMARY KEY, patient_id INT, visit_id INT NULL, doc_type ENUM('medical_certificate','symptom_report','lab_request','referral','operation_report') NOT NULL, title VARCHAR(200), department_to VARCHAR(150), doctor_to VARCHAR(150), content TEXT, created_by INT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(patient_id) REFERENCES patients(id) ON DELETE CASCADE, FOREIGN KEY(visit_id) REFERENCES visits(id) ON DELETE SET NULL);
CREATE TABLE ai_risk_assessments(id INT AUTO_INCREMENT PRIMARY KEY, patient_id INT, risk_type VARCHAR(80), score INT, level VARCHAR(30), reasons TEXT, recommendation TEXT, assessed_at DATETIME, FOREIGN KEY(patient_id) REFERENCES patients(id) ON DELETE CASCADE);
CREATE TABLE ventilator_cases(id INT AUTO_INCREMENT PRIMARY KEY, patient_id INT, visit_id INT NULL, recorded_at DATETIME, ventilator_id VARCHAR(100), mode_name VARCHAR(80), pip DECIMAL(6,2), peep DECIMAL(6,2), vte DECIMAL(8,2), flow DECIMAL(8,2), pressure_avg DECIMAL(8,2), rr INT, ai_score INT, ai_level VARCHAR(30), ai_note TEXT, FOREIGN KEY(patient_id) REFERENCES patients(id) ON DELETE CASCADE, FOREIGN KEY(visit_id) REFERENCES visits(id) ON DELETE SET NULL);
CREATE TABLE ventilator_waveforms(id INT AUTO_INCREMENT PRIMARY KEY, case_id INT, sample_time DECIMAL(10,3), flow_l_min DECIMAL(10,3), pressure_cmh2o DECIMAL(10,3), volume_ml DECIMAL(10,3), FOREIGN KEY(case_id) REFERENCES ventilator_cases(id) ON DELETE CASCADE);
CREATE TABLE support_tickets(id INT AUTO_INCREMENT PRIMARY KEY, user_role VARCHAR(30), user_name VARCHAR(150), category VARCHAR(150), message TEXT, status ENUM('open','in_progress','closed') DEFAULT 'open', created_at DATETIME DEFAULT CURRENT_TIMESTAMP);

-- v9 extra dashboard counts: keep Patients=100, Visits=312, High Risk=18, ICU=10 for clickable dashboard
